#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        unsigned int P,Q,R; scanf("%u %u %u", &P, &Q, &R);
        uint64_t ans = 1;
        for(int i=0;i<20;i++){
            int p = (P>>i)&1;
            int q = (Q>>i)&1;
            int r = (R>>i)&1;
            int ways = 0;
            if(p==0 && q==0 && r==0) ways = 1;
            else if(p==0 && q==1 && r==1) ways = 1;
            else if(p==1 && q==1 && r==0) ways = 1;
            else if(p==1 && q==0 && r==1) ways = 1;
            else if(p==1 && q==1 && r==1) ways = 4;
            else { ways = 0; ans = 0; break; }
            ans *= ways;
        }
        printf("%llu\n", ans);
    }
    return 0;
}

