            r = (R>>i)&1
            if p==0 and q==0 and r==0:
                ways = 1
            elif p==0 and q==1 and r==1:
                ways = 1
            elif p==1 and q==1 and r==0:
                ways = 1
            elif p==1 and q==0 and r==1:
                ways = 1
            elif p==1 and q==1 and r==1:
                ways = 4
